class Solution {
    public char kthCharacter(long k, int[] operations) {
        long length = 1;
        for (int operation : operations) {
            if (operation == 0) {
                length *= 2;
            } else {
                length *= 2;
            }
        }
        return findKthCharacter(k, operations, 0, 1);
    }

    private char findKthCharacter(long k, int[] operations, int index, long length) {
        if (index == operations.length) {
            return 'a';
        }
        if (k <= length) {
            if (operations[index] == 0) {
                return findKthCharacter(k, operations, index + 1, length / 2);
            } else {
                if (k <= length / 2) {
                    return findKthCharacter(k, operations, index + 1, length / 2);
                } else {
                    char c = findKthCharacter(k - length / 2, operations, index + 1, length / 2);
                    if (c == 'z') {
                        return 'a';
                    } else {
                        return (char) (c + 1);
                    }
                }
            }
        } else {
            return findKthCharacter(k - length, operations, index + 1, length);
        }
    }
}
